+                    let kwargs = PyDict::new(py);
+                    kwargs.set_item("order", "F")?;
+                    kwargs
+                }),
+            )?;
+            let theirs_fortran = numpy_asanyarray.call(
+                (ints.clone(),),
+                Some(&{
+                    let kwargs = PyDict::new(py);
+                    kwargs.set_item("order", "F")?;
+                    kwargs
+                }),
